#include<bits/stdc++.h>
using namespace std;
long long n=0;
long long s1[101];
long long c,ans=LLONG_MAX;
void dfs(long long x=1,long long sum=1)
{
    if(x>n)
    {
        if(sum>=c/sum)
        {
            ans=min(ans,sum);
        }
        return;
    }
    dfs(x+1,sum);
    dfs(x+1,sum*s1[x]);
}
int main()
{
    long long a,b;
    while(scanf("%lld%lld",&a,&b)==2)
    {
        memset(s1,0,sizeof(s1));
        c=b/a;
        n=0;
        ans=LLONG_MAX;
        long long c1=c;
        long long p=2;
        long long s2=0;
        if(c%p==0)
        {
            n=1;
            s1[1]=1;
        }
        while(c!=1)
        {
            if(c%p!=0)
            {
                s2=0;
                p++;
                if(c%p==0)
                {
                    n++;
                    s1[n]=1;
                }
            }
            else
            {
                s2++;
                c/=p;
                s1[n]*=p;
                // printf("p=%lld s1[p]=%lld c=%lld s2=%lld\n",p,s1[p],c,s2);
            }
        }
        c=c1;
        // printf("%lld\n",c);
        dfs();
        printf("%lld %lld\n",(c/ans)*a,ans*a);
    }
    return 0;
}
